import UIKit
import LocalAuthentication

class BankingViewController: UIViewController {
    
    private var bankAccount: BankAccount = BankAccount(initialBalance: 1000.00)
    
    override func viewDidLoad() {
        super.viewDidLoad()
    }
    
    // Display current balance
    func displayCurrentBalance() {
        let balance: Double = bankAccount.getBalance()
        print("Your current balance is \(balance)")
    }
    
    // Process transaction after authentication
    func processTransaction(transaction: Transaction) {
        let authenticationContext = LAContext()
        var error: NSError?
        
        if authenticationContext.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) {
            let reason = "Authenticate for the transaction"
            
            authenticationContext.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { [weak self] (success, authenticationError) in
                
                DispatchQueue.main.async {
                    if success {
                        self?.bankAccount.performTransaction(transaction: transaction)
                        self?.displayCurrentBalance()
                    } else {
                        print("Authentication Failed")
                    }
                }
            }
        } else {
            print("Touch ID/ Face ID may not be configured")
        }   
    }
}

class BankAccount {
    private var balance: Double
    
    init(initialBalance: Double) {
        self.balance = initialBalance
    }
    
    func getBalance() -> Double {
        return balance
    }
    
    func performTransaction(transaction: Transaction) {
        balance = transaction.perform(withBalance: balance)
    }
}

protocol Transaction {
    func perform(withBalance balance: Double) -> Double
}

class DebitTransaction: Transaction {
    private var amount: Double
    
    init(amount: Double) {
        self.amount = amount
    }
    
    func perform(withBalance balance: Double) -> Double {
        return balance - amount
    }
}

class CreditTransaction: Transaction {
    private var amount: Double
    
    init(amount: Double) {
        self.amount = amount
    }
    
    func perform(withBalance balance: Double) -> Double {
        return balance + amount
    }
}